/**
 * explorer.js — Semantic Space Explorer
 *
 * Renders an interactive 2D scatter plot of all artifacts using
 * precomputed UMAP coordinates from data files generated by the pipeline.
 *
 * Data files expected in website/assets/data/:
 *   - artifacts.json   : array of artifact records (id, type, title, year, city, case_study_flag, ...)
 *   - projections.json : array of {id, x, y, cluster} objects
 *
 * Uses Plotly.js loaded via CDN (no build step needed for GitHub Pages).
 *
 * TODO: Load Plotly and wire up the interactive controls once data is ready.
 */

(function () {
  const container = document.getElementById("semantic-explorer");
  if (!container) return;

  // Load both data files in parallel
  Promise.all([
    fetch("assets/data/artifacts.json").then((r) => r.json()),
    fetch("assets/data/projections.json").then((r) => r.json()),
  ])
    .then(([artifacts, projections]) => {
      renderExplorer(container, artifacts, projections);
    })
    .catch((err) => {
      container.innerHTML =
        '<p style="padding:2em; color:#c00;">Could not load data files. ' +
        "Run the pipeline first to generate <code>artifacts.json</code> and " +
        "<code>projections.json</code>.</p>";
      console.error("Explorer data load error:", err);
    });

  function renderExplorer(container, artifacts, projections) {
    // Build a lookup from id → artifact metadata
    const artifactMap = {};
    for (const a of artifacts) {
      artifactMap[a.id] = a;
    }

    // Group projections by artifact type for separate trace colors
    const types = ["paper", "patent", "project", "part"];
    const colors = {
      paper: "#4e79a7",
      patent: "#f28e2b",
      project: "#59a14f",
      part: "#e15759",
    };

    const traces = types.map((type) => {
      const pts = projections.filter(
        (p) => artifactMap[p.id] && artifactMap[p.id].type === type
      );
      return {
        x: pts.map((p) => p.x),
        y: pts.map((p) => p.y),
        mode: "markers",
        type: "scatter",
        name: type.charAt(0).toUpperCase() + type.slice(1) + "s",
        marker: { color: colors[type], size: 5, opacity: 0.7 },
        text: pts.map((p) => {
          const a = artifactMap[p.id] || {};
          return `${a.title || p.id} (${a.year || "?"})`;
        }),
        hovertemplate: "%{text}<extra></extra>",
      };
    });

    const layout = {
      title: "Semantic Space — All Artifacts",
      showlegend: true,
      xaxis: { title: "UMAP 1", showgrid: false, zeroline: false },
      yaxis: { title: "UMAP 2", showgrid: false, zeroline: false },
      margin: { t: 40, l: 40, r: 20, b: 40 },
    };

    // Plotly must be loaded via CDN in the Quarto page
    if (typeof Plotly !== "undefined") {
      Plotly.newPlot(container, traces, layout, { responsive: true });
    } else {
      container.innerHTML =
        '<p style="padding:2em; color:#888;">Plotly.js is not loaded. ' +
        "Add a Plotly CDN script tag to explorer.qmd.</p>";
    }
  }
})();
